"use client"

import { useState } from "react"
import { useForm } from "react-hook-form"
import { Form, FormControl, FormField, FormItem, FormMessage } from "@/components/ui/form"
import { Button } from "@/components/ui/button"
import { Checkbox } from "@/components/ui/checkbox"
import Link from "next/link"

interface LoginFormProps {
  onSuccess: (token: string, userData: { id: number; name: string; email: string }) => void
}

interface LoginFormValues {
  name: string
  password: string
  rememberMe: boolean
}

export function LoginForm({ onSuccess }: LoginFormProps) {
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const form = useForm<LoginFormValues>({
    defaultValues: {
      name: "",
      password: "",
      rememberMe: false,
    },
  })

  async function onSubmit(values: LoginFormValues) {
    setIsLoading(true)
    setError(null)

    try {
      const response = await fetch("/api/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: values.name,
          password: values.password,
        }),
      })

      if (!response.ok) {
        throw new Error("Invalid credentials")
      }

      const data = await response.json()
      onSuccess(data.token, data.user)
    } catch (err) {
      setError(err instanceof Error ? err.message : "An error occurred")
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
        {/* Name/Email Field */}
        <FormField
          control={form.control}
          name="name"
          rules={{ required: "Name is required" }}
          render={({ field }) => (
            <FormItem>
              <FormControl>
                <div className="border-b border-slate-500/40 pb-3">
                  <input
                    {...field}
                    placeholder="Name"
                    className="w-full bg-transparent text-slate-100 placeholder-slate-500 focus:outline-none text-sm not-italic"
                    type="text"
                  />
                </div>
              </FormControl>
              <FormMessage className="text-red-400" />
            </FormItem>
          )}
        />

        {/* Password Field */}
        <FormField
          control={form.control}
          name="password"
          rules={{ required: "Password is required" }}
          render={({ field }) => (
            <FormItem>
              <FormControl>
                <div className="border-b border-slate-500/40 pb-3">
                  <input
                    {...field}
                    placeholder="Password"
                    type="password"
                    className="w-full bg-transparent text-slate-100 placeholder-slate-500 focus:outline-none text-sm not-italic"
                  />
                </div>
              </FormControl>
              <FormMessage className="text-red-400" />
            </FormItem>
          )}
        />

        {/* Sign In Button */}
        <Button
          type="submit"
          disabled={isLoading}
          className="w-full bg-emerald-500 hover:bg-emerald-600 text-slate-900 font-bold py-2 rounded-none mt-10 tracking-widest"
        >
          {isLoading ? "SIGNING IN..." : "SIGN IN"}
        </Button>

        {/* Remember Me & Forgot Password */}
        <div className="flex items-center justify-between pt-6">
          <label className="flex items-center gap-2 cursor-pointer text-slate-300 text-xs tracking-wide">
            <Checkbox
              checked={form.watch("rememberMe")}
              onCheckedChange={(checked) => form.setValue("rememberMe", checked as boolean)}
              className="border-slate-500"
            />
            Remember Me
          </label>
          <Link
            href="/forgot-password"
            className="text-slate-300 hover:text-slate-100 text-xs tracking-wide transition-colors"
          >
            Forgot password
          </Link>
        </div>
      </form>
    </Form>
  )
}
